import{_ as a,o as b,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"赤兔","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/载具/2.C级/赤兔.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/载具/2.C级/赤兔.md"}'),s={name:"4.资源分区/7.物品与装备/7.载具及随从/载具/2.C级/赤兔.md"};function o(d,e,l,i,_,c){return b(),t("div",null,[...e[0]||(e[0]=[r("h1",{id:"赤兔",tabindex:"-1"},[p("赤兔 "),r("a",{class:"header-anchor",href:"#赤兔","aria-label":'Permalink to "赤兔"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风027")])])],-1),n('<h1 id="赤兔-1" tabindex="-1">赤兔 <a class="header-anchor" href="#赤兔-1" aria-label="Permalink to &quot;赤兔&quot;">​</a></h1><p>赤兔</p><p>此马全身似锦缎火炭、脑门有撮白月光，有股棕毛覆盖其上，耳下有骨突起，腹侧四处旋状棕毛，四蹄之下弯曲如钩。此谓头上长角，肚下生鳞，蹄下有爪。山冈之上犹如猛虎，沧海之中犹如蛟龙。<br> 特殊的：该坐骑可以由神威战马差价升级而来。<br> C+1000<br> 坐骑<br> 介绍：<br> 基本能力值<br> 智力 6<br> 感知 9<br> 决心 6</p><p>力量 11<br> 敏捷 11<br> 耐力 9</p><p>风度 6<br> 操控 6<br> 沉着 9</p><p>技能<br> 知识1<br> 器用1<br> 手艺1<br> 专注5-意志5</p><p>运动8-反射8<br> 生存8-强韧8，求生5<br> 射击1<br> 武技5-蹄5</p><p>洞察5-侦察5<br> 隐秘5-潜藏5<br> 表达1<br> 社交1</p><p>衍生属性值<br> ▓▓▓▓衍生属性值<br> 相貌:3<br> ▓体积 7<br> ▓速度70 （力量【11】+敏捷【11】+体积【7】+每1点敏捷上的附加获得3移动速度）+蹄下生风【35】<br> ▓先攻2rd10+20 （敏捷【11】+沉着【9】）<br> ▓防御 9+1（敏捷感知的平均值【9】+较高者的附加成功【2】）<br> ▓生命值17 （耐力【9】+体积【7】+耐力附加【1 】×5）<br> ▓意志力池17 （决心【6】+沉着【9】+决心附加【1 】×2）<br> ▓意志17+3 （决心【6】+专注5+意志【5】）+传风1<br> ▓反射28+4 （敏捷【11】+运动8+反射【8】）+传风1<br> ▓强韧25+3 （耐力【9】+生存8+强韧【8】）+传风1<br> ▓侦查 20+2（感知【9】+洞察5+侦查【5】）+传风1<br> ▓敏感范围200 （感知【9】*20米+感知上的附加成功【1 】*20米）<br> 攻击预设：<br> 蹄子：力量11+武技5+蹄5+武器伤害3+传奇力2+传奇风1＝27+6</p><p>防御预设：<br> 基防9+2</p><p>随从特性：<br> 【龙精虎猛】：赤兔体积提升2点，形态更为神俊。<br> 【蹄下生风】：赤兔的蹄子视为3l的天生武器，同时赤兔速度提升35米。<br> 【一骑当千】：赤兔免疫B级困难地形和B级环境效果，在战斗中，只要骑士没有停止移动，在自身回合结束时骑士都将获得1点闪避防御，这些防御持续到战斗结束，至多获得15点闪避防御。</p><p>——————————————<br> 赤兔专属技艺<br> C+1000<br> 【不可阻挡】<br> 当赤兔乘骑者因为【一骑当千】获得闪避防御达到2点以上时，驾驭赤兔冲锋时，基础防御不会承受减值，同时无视多次攻击减值。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',14)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
